from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
import re

class LicenseCategory(Enum):
    PERMISSIVE = 'permissive'       # MIT, Apache-2.0, BSD-2/3-Clause
    WEAK_COPYLEFT = 'weak_copyleft' # LGPL, MPL-2.0 — file-level copyleft only
    STRONG_COPYLEFT = 'strong_copyleft'  # GPL-2.0, GPL-3.0, AGPL-3.0
    PROPRIETARY = 'proprietary'     # commercial, all-rights-reserved
    UNKNOWN = 'unknown'

SPDX_CATEGORY_MAP = {
    'MIT': LicenseCategory.PERMISSIVE,
    'Apache-2.0': LicenseCategory.PERMISSIVE,
    'BSD-2-Clause': LicenseCategory.PERMISSIVE,
    'BSD-3-Clause': LicenseCategory.PERMISSIVE,
    'ISC': LicenseCategory.PERMISSIVE,
    'LGPL-2.1-only': LicenseCategory.WEAK_COPYLEFT,
    'LGPL-2.1-or-later': LicenseCategory.WEAK_COPYLEFT,
    'MPL-2.0': LicenseCategory.WEAK_COPYLEFT,
    'GPL-2.0-only': LicenseCategory.STRONG_COPYLEFT,
    'GPL-3.0-only': LicenseCategory.STRONG_COPYLEFT,
    'AGPL-3.0-only': LicenseCategory.STRONG_COPYLEFT,
}

@dataclass
class OSSComponent:
    package_name: str
    version: str
    spdx_id: str
    used_as: str   # 'runtime', 'dev', 'model', 'dataset', 'sdk'
    distribution: str  # 'saas', 'on-prem', 'embedded'

    @property
    def license_category(self) -> LicenseCategory:
        return SPDX_CATEGORY_MAP.get(self.spdx_id, LicenseCategory.UNKNOWN)

    @property
    def agpl_network_risk(self) -> bool:
        return (self.spdx_id == 'AGPL-3.0-only'
                and self.distribution == 'saas'
                and self.used_as == 'runtime')

    def gate1_license_check(self) -> dict:
        category = self.license_category
        if category == LicenseCategory.PERMISSIVE:
            return {'result': 'pass', 'action': None}
        if category == LicenseCategory.STRONG_COPYLEFT:
            if self.agpl_network_risk:
                return {'result': 'reject', 'action': 'legal_review_required',
                        'reason': 'AGPL SaaS distribution triggers copyleft on server-side code'}
            return {'result': 'reject', 'action': 'legal_review_required',
                    'reason': 'GPL copyleft may contaminate proprietary code'}
        if category == LicenseCategory.WEAK_COPYLEFT:
            return {'result': 'conditional', 'action': 'dynamic_linking_required',
                    'reason': 'LGPL/MPL: maintain clear boundary between OSS and proprietary code'}
        return {'result': 'hold', 'action': 'license_identification',
                'reason': 'License not recognised — manual classification required'}

@dataclass
class OSSUsageRecord:
    component: OSSComponent
    purpose: str
    agentic_role: str  # 'llm_sdk', 'tool_executor', 'memory_store', 'orchestrator', 'other'
    data_exposure: list  # personal data categories the component may process
    approval_status: str = 'pending'
    approved_by: Optional[str] = None
    conditions: list = field(default_factory=list)

    @property
    def data_risk_elevated(self) -> bool:
        high_risk_categories = {
            'health', 'financial', 'biometric', 'location', 'children'
        }
        return bool(set(self.data_exposure) & high_risk_categories)

    @property
    def agentic_risk_score(self) -> int:
        # Higher score for components in the critical agentic path
        scores = {
            'llm_sdk': 3,        # model weights / API key exposure
            'orchestrator': 3,   # controls agent routing and tool dispatch
            'tool_executor': 2,  # executes external tool calls
            'memory_store': 2,   # persists user conversation data
            'other': 1,
        }
        base = scores.get(self.agentic_role, 1)
        return base + (2 if self.data_risk_elevated else 0)

    def approve(self, reviewer: str, conditions: list = None) -> None:
        self.approval_status = 'approved'
        self.approved_by = reviewer
        self.conditions = conditions or []

    def to_sbom_entry(self) -> dict:
        return {
            'name': self.component.package_name,
            'version': self.component.version,
            'spdxId': self.component.spdx_id,
            'licenseCategory': self.component.license_category.value,
            'agenticRole': self.agentic_role,
            'agenticRiskScore': self.agentic_risk_score,
            'approvalStatus': self.approval_status,
            'conditions': self.conditions,
        }

from typing import List

class OSSPolicyEnforcer:
    def __init__(self, sbom: List[OSSUsageRecord]):
        self.sbom = sbom

    def run_gates(self) -> List[dict]:
        results = []
        for record in self.sbom:
            gate1 = record.component.gate1_license_check()
            gate2 = self._gate2_security_check(record.component)
            gate3 = self._gate3_ip_data_check(record)
            overall = 'pass'
            if any(r['result'] == 'reject' for r in [gate1, gate2, gate3]):
                overall = 'reject'
            elif any(r['result'] in ('hold', 'conditional')
                     for r in [gate1, gate2, gate3]):
                overall = 'conditional'
            results.append({
                'package': record.component.package_name,
                'gate1_license': gate1,
                'gate2_security': gate2,
                'gate3_ip_data': gate3,
                'overall': overall,
            })
        return results

    def _gate2_security_check(self, comp: OSSComponent) -> dict:
        # In practice, query OSV / Grype API for CVEs
        # Here we return the schema that integrates with scan output
        return {
            'result': 'pass',
            'action': None,
            'note': 'Pass OSV scan with no CRITICAL/HIGH CVEs unpatched > 30 days',
        }

    def _gate3_ip_data_check(self, record: OSSUsageRecord) -> dict:
        if record.data_risk_elevated and record.agentic_role == 'memory_store':
            return {
                'result': 'conditional',
                'action': 'dpia_required',
                'reason': 'High-risk personal data in agentic memory store',
            }
        return {'result': 'pass', 'action': None}

# Usage
enforcer = OSSPolicyEnforcer(sbom=[
    OSSUsageRecord(
        component=OSSComponent(
            package_name='langchain-core', version='0.2.10',
            spdx_id='MIT', used_as='runtime', distribution='saas'),
        purpose='LLM orchestration framework',
        agentic_role='orchestrator',
        data_exposure=['conversation_text'],
    ),
])
print(enforcer.run_gates())
